using System.Threading.Channels;

public class EventProcessor : IAsyncDisposable
{
    private readonly Channel<string> _channel = Channel.CreateUnbounded<string>(
        new UnboundedChannelOptions { SingleReader = true });

    private readonly CancellationTokenSource _cts = new();
    private Task? _runTask;

    public void Start()
    {
        // Task.Run replaces manual Thread creation;
        // the channel reader blocks asynchronously — no ManualResetEvent needed.
        _runTask = Task.Run(() => RunLoopAsync(_cts.Token));
    }

    private async Task RunLoopAsync(CancellationToken ct)
    {
        try
        {
            await foreach (var item in _channel.Reader.ReadAllAsync(ct))
            {
                Handle(item);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on shutdown — drain remaining items if desired.
        }
    }

    public void Enqueue(string item)
    {
        if (!_channel.Writer.TryWrite(item))
            throw new InvalidOperationException("Channel is closed.");
    }

    public async ValueTask StopAsync(TimeSpan? timeout = null)
    {
        _channel.Writer.Complete();             // signal no more items
        await _cts.CancelAsync();               // unblock if waiting for next item

        var delay = timeout ?? TimeSpan.FromSeconds(5);
        if (_runTask is not null)
        {
            using var timeoutCts = new CancellationTokenSource(delay);
            try
            {
                await _runTask.WaitAsync(timeoutCts.Token);
            }
            catch (TimeoutException)
            {
                // Loop didn't finish in time — it will still end once
                // the current Handle() call returns. Log a warning.
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        await StopAsync();
        _cts.Dispose();
    }

    private void Handle(string item)
    {
        // Your processing logic here.
        Console.WriteLine($"Processing: {item}");
    }
}

